using ByteForge.Toolkit;

// Initialize database connection
var connectionString = "Server=localhost;Database=MyApp;Integrated Security=true;";
var db = new DBAccess(connectionString);

// Execute a simple query
var userCount = db.GetValue<int>("SELECT COUNT(*) FROM Users");
Console.WriteLine($"Total users: {userCount}");

// Execute query with parameters
var activeUsers = db.GetRecords(
    "SELECT * FROM Users WHERE IsActive = @active AND CreatedDate > @date",
    true, DateTime.Now.AddDays(-30) );

Console.WriteLine($"Active users in last 30 days: {activeUsers.Rows.Count}");

// Execute stored procedure
var results = db.GetRecords("exec GetUsersByDepartment @DepartmentID, @IncludeInactive",
    5, false );

foreach (DataRow row in results.Rows)
{
    Console.WriteLine($"User: {row["FirstName"]} {row["LastName"]}");
}

var db = new DBAccess(connectionString);

using (var transaction = db.BeginTransaction())
{
    try
    {
        // Create new user
        var userId = db.GetValue<int>(
            "INSERT INTO Users (FirstName, LastName, Email) OUTPUT INSERTED.UserId VALUES (@first, @last, @email)",
            new { first = "John", last = "Doe", email = "john.doe@company.com" },
            transaction
        );

        // Add user to role
        db.ExecuteQuery(
            "INSERT INTO UserRoles (UserId, RoleId) VALUES (@userId, @roleId)",
            new { userId = userId, roleId = 2 },
            transaction
        );

        // Create user profile
        db.ExecuteQuery(
            "INSERT INTO UserProfiles (UserId, Department, StartDate) VALUES (@userId, @dept, @date)",
            new { userId = userId, dept = "Engineering", date = DateTime.Now },
            transaction
        );

        // Commit all changes
        transaction.Commit();
        Console.WriteLine($"User created successfully with ID: {userId}");
    }
    catch (Exception ex)
    {
        transaction.Rollback();
        Console.WriteLine($"Transaction failed: {ex.Message}");
        throw;
    }
}

var db = new DBAccess(connectionString);
var cancellationToken = new CancellationTokenSource(TimeSpan.FromMinutes(5)).Token;

try
{
    // Async query execution
    var users = await db.GetDataTableAsync(
        "SELECT * FROM Users WHERE Department = @dept ORDER BY LastName",
        new { dept = "Sales" },
        cancellationToken
    );

    Console.WriteLine($"Found {users.Rows.Count} sales users");

    // Async bulk update
    await db.ExecuteNonQueryAsync(
        "UPDATE Users SET LastLoginDate = @date WHERE Department = @dept",
        new { date = DateTime.Now, dept = "Sales" },
        cancellationToken
    );

    // Async scalar value
    var totalSalesUsers = await db.GetValueAsync<int>(
        "SELECT COUNT(*) FROM Users WHERE Department = 'Sales'",
        cancellationToken
    );

    Console.WriteLine($"Updated {totalSalesUsers} sales users");
}
catch (OperationCanceledException)
{
    Console.WriteLine("Database operation was cancelled");
}
catch (Exception ex)
{
    Console.WriteLine($"Database error: {ex.Message}");
}

// Define entity class with DB column mapping
public class Product
{
    [DBColumn("ProductId", isPrimaryKey: true, isIdentity: true)]
    public int Id { get; set; }

    [DBColumn("ProductName")]
    public string Name { get; set; }

    [DBColumn("CategoryId")]
    public int CategoryId { get; set; }

    [DBColumn("UnitPrice")]
    public decimal Price { get; set; }

    [DBColumn("UnitsInStock")]
    public int Stock { get; set; }

    [DBColumn("CreatedDate")]
    public DateTime CreatedDate { get; set; } = DateTime.Now;
}

// Bulk insert with progress reporting
var db = new DBAccess(connectionString);
var bulkProcessor = new BulkDbProcessor<Product>(db);

// Subscribe to progress events
bulkProcessor.ProgressReported += (sender, e) =>
{
    Console.WriteLine($"Processed {e.ProcessedCount}/{e.TotalCount} ({e.PercentComplete:F1}%)");
};

// Create sample data
var products = new List<Product>();
for (int i = 1; i <= 10000; i++)
{
    products.Add(new Product
    {
        Name = $"Product {i}",
        CategoryId = (i % 5) + 1,
        Price = Math.Round((decimal)(10 + (i % 100)), 2),
        Stock = i % 50
    });
}

// Bulk insert all products
await bulkProcessor.BulkInsertAsync("Products", products);
Console.WriteLine("Bulk insert completed!");

public class Customer
{
    [DBColumn("CustomerId", isPrimaryKey: true)]
    public string Id { get; set; }

    [DBColumn("CompanyName")]
    public string CompanyName { get; set; }

    [DBColumn("ContactName")]
    public string ContactName { get; set; }

    [DBColumn("Phone")]
    public string Phone { get; set; }

    [DBColumn("LastUpdated")]
    public DateTime LastUpdated { get; set; } = DateTime.Now;
}

var bulkProcessor = new BulkDbProcessor<Customer>(db);

// Sample customer updates
var customers = new List<Customer>
{
    new Customer { Id = "ALFKI", CompanyName = "Alfreds Futterkiste Updated", Phone = "555-1234" },
    new Customer { Id = "ANATR", CompanyName = "Ana Trujillo Emparedados", Phone = "555-5678" },
    new Customer { Id = "NEWCO", CompanyName = "New Company LLC", Phone = "555-9999" }
};

// Bulk update existing customers by primary key
var updateResult = await bulkProcessor.BulkUpdateAsync("Customers", customers);
Console.WriteLine($"Updated {updateResult.RowsAffected} customers");

// Bulk upsert (insert new, update existing)
var upsertResult = await bulkProcessor.BulkUpsertAsync("Customers", customers, 
    updateColumns: new[] { "CompanyName", "ContactName", "Phone", "LastUpdated" });

Console.WriteLine($"Upserted {upsertResult.RowsAffected} customers");

using ByteForge.Toolkit;

var csvReader = new CSVReader();

// Subscribe to progress events for large files
csvReader.ProgressReported += (sender, e) =>
{
    Console.WriteLine($"Reading: {e.PercentComplete:F1}% ({e.RecordsProcessed} records)");
};

// Read CSV file with automatic format detection
csvReader.ReadFile("customers.csv");

Console.WriteLine($"Loaded {csvReader.Records.Count} records");
Console.WriteLine($"Columns: {string.Join(", ", csvReader.Headers)}");

// Access data by column name
foreach (var record in csvReader.Records)
{
    var customerId = record["CustomerId"];
    var companyName = record["CompanyName"];
    var contactName = record["ContactName"];
    var phone = record["Phone"];

    Console.WriteLine($"{customerId}: {companyName} - {contactName} ({phone})");
}

var csvReader = new CSVReader();

// Configure custom CSV format
var format = new CSVFormat
{
    Delimiter = ';',           // Use semicolon delimiter
    QuoteCharacter = '"',      // Double quotes for text
    EscapeCharacter = '\\',    // Backslash for escaping
    HasHeaders = true,         // First row contains headers
    TrimFields = true,         // Trim whitespace
    SkipEmptyLines = true,     // Skip blank lines
    Encoding = Encoding.UTF8   // UTF-8 encoding
};

csvReader.ReadFile("data.csv", format);

// Process records with type conversion
foreach (var record in csvReader.Records)
{
    try
    {
        var id = int.Parse(record["Id"]);
        var name = record["Name"];
        var price = decimal.Parse(record["Price"]);
        var date = DateTime.Parse(record["CreatedDate"]);

        Console.WriteLine($"ID: {id}, Name: {name}, Price: {price:C}, Date: {date:d}");
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error processing record: {ex.Message}");
    }
}

var csvWriter = new CSVWriter();

// Configure output format
var format = new CSVFormat
{
    Delimiter = ',',
    QuoteCharacter = '"',
    HasHeaders = true,
    Encoding = Encoding.UTF8
};

// Define headers
var headers = new[] { "ProductId", "ProductName", "Category", "Price", "InStock" };

// Sample data
var products = new[]
{
    new { Id = 1, Name = "Laptop Computer", Category = "Electronics", Price = 999.99m, Stock = true },
    new { Id = 2, Name = "Office Chair", Category = "Furniture", Price = 249.50m, Stock = false },
    new { Id = 3, Name = "Wireless Mouse", Category = "Electronics", Price = 29.99m, Stock = true }
};

// Write to CSV
csvWriter.WriteFile("products.csv", format, headers, products.Select(p => new object[]
{
    p.Id,
    p.Name,
    p.Category,
    p.Price,
    p.Stock ? "Yes" : "No"
}));

Console.WriteLine("CSV file written successfully");

